import{_ as t,o as e,c as i,a2 as n}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Theme Blocks","description":"FXT Theme - Blocks","frontmatter":{"title":"Theme Blocks","description":"FXT Theme - Blocks","weight":80,"extra":{"order":80},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/blocks"}],["meta",{"property":"og:title","content":"Theme Blocks"}],["meta",{"property":"og:description","content":"FXT Theme - Blocks"}],["meta",{"name":"twitter:title","content":"Theme Blocks"}],["meta",{"name":"twitter:description","content":"FXT Theme - Blocks"}]]},"headers":[],"relativePath":"docs/fxt/blocks.md","filePath":"docs/fxt/blocks.md"}'),s={name:"docs/fxt/blocks.md"};function r(l,o,a,c,g,d){return e(),i("div",null,[...o[0]||(o[0]=[n('<h1 id="fxt-theme-blocks" tabindex="-1">FXT Theme Blocks <a class="header-anchor" href="#fxt-theme-blocks" aria-label="Permalink to &quot;FXT Theme Blocks&quot;">​</a></h1><p>There are multiple blocks available for you to present your website information.</p><hr><h2 id="using-blocks" tabindex="-1">Using Blocks <a class="header-anchor" href="#using-blocks" aria-label="Permalink to &quot;Using Blocks&quot;">​</a></h2><p>Here are the blocks available in FXT theme:</p><ul><li>Broker Comparison Table</li><li>Broker Comparison Links</li><li>Broker Listing</li><li>FAQ</li><li>Recent Posts</li><li>Section Heading</li><li>Section Conclusion</li></ul><p>There are other blocks that are available in broker pages only: <a href="/docs/fxt/broker-page-blocks">Broker Page Blocks</a></p><h3 id="broker-comparison-table-block" tabindex="-1">Broker Comparison Table Block <a class="header-anchor" href="#broker-comparison-table-block" aria-label="Permalink to &quot;Broker Comparison Table Block&quot;">​</a></h3><p>To add a new comparison table simply click on the <strong>+</strong> (Add block) sign and select <strong>Broker Comparison Table</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new table edit section will appear. Click <strong>Add Broker</strong> to add as many brokers as you want. Select the style from the dropdown menu and configure the display options.</p><p>Broker Comparison Table block offers you multiple styles and options. You can display tables with different layouts and configure various display settings.</p><h3 id="broker-comparison-links-block" tabindex="-1">Broker Comparison Links Block <a class="header-anchor" href="#broker-comparison-links-block" aria-label="Permalink to &quot;Broker Comparison Links Block&quot;">​</a></h3><p>To add a new comparison links block simply click on the <strong>+</strong> (Add block) sign and select <strong>Broker Comparison Links</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new comparison links edit section will appear. Add the brokers you want to compare and configure the display options.</p><h3 id="listing-block" tabindex="-1">Listing Block <a class="header-anchor" href="#listing-block" aria-label="Permalink to &quot;Listing Block&quot;">​</a></h3><p>To add a new listing block simply click on the <strong>+</strong> (Add block) sign and select <strong>Broker Listing</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new listing edit section will appear. This is one of the most important blocks in FXT theme, allowing you to display broker listings with various configurations.</p><p><strong>Broker Selection</strong>:</p><ul><li><strong>Manual</strong>: Select specific brokers from a list</li><li><strong>Filter &amp; Match</strong>: Automatically filter brokers based on criteria</li></ul><p><strong>Filter Options</strong> (when using Filter &amp; Match):</p><ul><li><strong>Category</strong>: Filter by broker category</li><li><strong>Tags</strong>: Filter by broker tags</li><li><strong>Country Support</strong>: Filter by country (including visitor&#39;s country)</li><li><strong>Regulation</strong>: Filter by regulatory body</li><li><strong>Order</strong>: Sort by date, name, rating, etc.</li><li><strong>Order By</strong>: Choose sorting criteria</li></ul><p><strong>Load More Options</strong>:</p><ul><li><strong>Enable Load More</strong>: Show initial number of brokers with load more button</li><li><strong>Initial Count</strong>: Number of brokers to show initially</li><li><strong>Load More Count</strong>: Number of additional brokers to load</li></ul><p><strong>Listing Types</strong>:</p><ul><li><strong>Listing 1</strong>: Basic listing layout</li><li><strong>Listing 2</strong>: Three-column layout with customizable fields</li><li><strong>Listing 3</strong>: Three-column layout with different styling</li><li><strong>Listing 4</strong>: Grid layout (2 columns)</li><li><strong>Listing 5</strong>: Single field display</li><li><strong>Listing 6</strong>: Section-based layout with multiple sections</li><li><strong>Listing 7</strong>: Grid layout (3 columns)</li><li><strong>Listing 8</strong>: Grid layout (3 columns) with different styling</li></ul><p><strong>Field Options</strong> (for applicable listing types):</p><ul><li>Minimum Deposit, Deposit Fees, Minimum Trade Size</li><li>Average Spread, Maximum Leverage, Trading Instruments</li><li>Social Trading, Swap-free Accounts, Negative Balance Protection</li><li>VPS Program, PAMM Accounts</li></ul><p><strong>Section Options</strong> (for Listing 6):</p><ul><li>Regulations, Trading Conditions, Trading Instruments</li><li>Trading Tools, Payment Options, Customer Support</li></ul><p><strong>Display Options</strong>:</p><ul><li><strong>Logo Lazy Loading</strong>: Enable/disable lazy loading for broker logos</li></ul><h3 id="faq-block" tabindex="-1">FAQ Block <a class="header-anchor" href="#faq-block" aria-label="Permalink to &quot;FAQ Block&quot;">​</a></h3><p>To add a new FAQ block simply click on the <strong>+</strong> (Add block) sign and select <strong>FAQ</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new FAQ edit section will appear. Click <strong>Add Question</strong> to add FAQ items. For each FAQ item:</p><ul><li><strong>Question</strong>: Enter the question text</li><li><strong>Answer</strong>: Enter the answer using the rich text editor</li></ul><p><strong>Configuration Options</strong>:</p><ul><li><strong>Include Schema Markup</strong>: Enable/disable structured data for SEO (recommended to keep enabled)</li></ul><p>Important: If you have more than one FAQ blocks on a single page, make sure to disable the schema markup for all of them except one to avoid duplicate structured data.</p><h3 id="recent-posts-block" tabindex="-1">Recent Posts Block <a class="header-anchor" href="#recent-posts-block" aria-label="Permalink to &quot;Recent Posts Block&quot;">​</a></h3><p>To add a new posts block simply click on the <strong>+</strong> (Add block) sign and select <strong>Recent Posts</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new recent posts edit section will appear with the following configuration options:</p><p><strong>Display Options</strong>:</p><ul><li><strong>Number of Posts</strong>: Choose from 4, 6, or 9 posts to display</li><li><strong>Post Category</strong>: Select a specific category to filter posts (optional)</li><li><strong>Post Tags</strong>: Select specific tags to filter posts (optional)</li><li><strong>Lazy Load Images</strong>: Enable/disable lazy loading for post images (recommended for performance)</li></ul><h3 id="section-heading-block" tabindex="-1">Section Heading Block <a class="header-anchor" href="#section-heading-block" aria-label="Permalink to &quot;Section Heading Block&quot;">​</a></h3><p>To add a new section heading block simply click on the <strong>+</strong> (Add block) sign and select <strong>Section Heading</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new section heading edit section will appear with the following configuration options:</p><p><strong>Content Options</strong>:</p><ul><li><strong>Heading</strong>: Enter the main heading text (required)</li><li><strong>Subheading</strong>: Enter optional subheading text</li><li><strong>Rating Field</strong>: Choose a rating field to display (Trading Instruments, Platforms and Tools, Fees, Security and Fairness, Deposit and Withdrawal, Customer Service)</li><li><strong>Rating Value</strong>: Set a custom rating value to display</li></ul><hr><h3 id="section-conclusion-block" tabindex="-1">Section Conclusion Block <a class="header-anchor" href="#section-conclusion-block" aria-label="Permalink to &quot;Section Conclusion Block&quot;">​</a></h3><p>To add a new section conclusion block simply click on the <strong>+</strong> (Add block) sign and select <strong>Section Conclusion</strong> in <strong>FXT Blocks</strong> section.</p><p>In the content editor a new section conclusion edit section will appear with the following configuration option:</p><p><strong>Content</strong>:</p><ul><li><strong>Conclusion</strong>: Enter the conclusion text using the text area (supports line breaks)</li></ul><h2 id="adding-blocks-to-pages" tabindex="-1">Adding Blocks to Pages <a class="header-anchor" href="#adding-blocks-to-pages" aria-label="Permalink to &quot;Adding Blocks to Pages&quot;">​</a></h2><ol><li>Edit a page in WordPress</li><li>Click the <strong>+</strong> button to add a new block</li><li>Search for the desired block name in the <strong>FXT Blocks</strong> section</li><li>Click on the block to add it to your page</li></ol><hr><h2 id="block-customization" tabindex="-1">Block Customization <a class="header-anchor" href="#block-customization" aria-label="Permalink to &quot;Block Customization&quot;">​</a></h2><p>Most blocks require configuration in the block settings panel:</p><ol><li>Select the block in the editor</li><li>Use the block toolbar for quick actions</li><li>Configure block settings in the right sidebar</li><li>Use the block inspector for advanced options</li></ol><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/theme-options">Theme Options</a></p>',63)])])}const k=t(s,[["render",r]]);export{h as __pageData,k as default};
